const sym = String(($json.query && $json.query.symbol) || 'BTC').replace('USDT','').toUpperCase();
const trades = await this.helpers.httpRequest({ url: `https://api.binance.com/api/v3/aggTrades?symbol=${sym}USDT&limit=1000`, json: true });
let maxBuy=null, maxSell=null;
for (const t of trades) {
  const price=parseFloat(t.p), qty=parseFloat(t.q), quote=price*qty;
  if (t.m===false) { if(!maxBuy||quote>maxBuy.q){maxBuy={q:quote,price,qty};} }
  else { if(!maxSell||quote>maxSell.q){maxSell={q:quote,price,qty};} }
}
return [{ json: {
  symbol: sym,
  maior_compra_usdt: maxBuy?Math.round(maxBuy.q):0,
  maior_compra_qtd: maxBuy?Number(maxBuy.qty.toFixed(4)):0,
  maior_venda_usdt: maxSell?Math.round(maxSell.q):0,
  maior_venda_qtd: maxSell?Number(maxSell.qty.toFixed(4)):0,
  negociacoes_analisadas: trades.length,
  janela: 'negociacoes recentes (ultimas ~'+trades.length+' trades, nao o dia inteiro)'
} }];
